import hmac, hashlib, pytest
from types import SimpleNamespace
from app.middleware.auth import AuthMiddleware, Unauthorized

GATEWAY_SECRET = b"test-secret"

def _sign(uid: str) -> str:
    return hmac.new(GATEWAY_SECRET, uid.encode(), hashlib.sha256).hexdigest()

def _req(headers=None, cookies=None):
    return SimpleNamespace(headers=headers or {}, cookies=cookies or {})

@pytest.mark.parametrize("headers, should_raise", [
    ({"X-Gateway-User-Id": "alice"},                                         True),   # no signature
    ({"X-Gateway-User-Id": "alice", "X-Gateway-Signature": "deadbeef"},      True),   # bad signature
    ({"X-Gateway-User-Id": "alice", "X-Gateway-Signature": _sign("bob")},    True),   # signature for a different uid
    ({"X-User-Id": "alice"},                                                 True),   # legacy unsigned header must not be trusted
    ({"X-Gateway-User-Id": "alice", "X-Gateway-Signature": _sign("alice")},  False),  # valid — positive control
])
def test_gateway_header_requires_valid_hmac(headers, should_raise):
    mw = AuthMiddleware(secret=GATEWAY_SECRET, sessions={})
    if should_raise:
        with pytest.raises(Unauthorized):
            mw.resolve_user(_req(headers=headers))
    else:
        user = mw.resolve_user(_req(headers=headers))
        assert user.id == "alice"
```

Three things this pins down: (1) a gateway-uid header without a signature is rejected, (2) a wrong signature — including one validly signed for a *different* uid — is rejected, and (3) the unsigned `X-User-Id` legacy escape hatch stays closed. The last case is the positive control so the test can't pass by accident via "reject everything."
